<?php
 namespace WPAICG\Chat\Core\AIService\GenerateResponse; if (!defined('ABSPATH')) { exit; } function prepare_messages_for_api_logic(array $history, string $user_message_text): array { $messages_payload = []; $latest_user_message_obj_for_stateful = null; $last_openai_response_id_from_history = null; foreach ($history as $msg) { $role = ($msg['role'] === 'bot') ? 'assistant' : $msg['role']; $content = isset($msg['content']) ? trim($msg['content']) : ''; if ($content !== '' && in_array($role, ['system', 'user', 'assistant'])) { $messages_payload[] = ['role' => $role, 'content' => $content]; if ($role === 'user' && $msg['content'] === $user_message_text) { $latest_user_message_obj_for_stateful = ['role' => 'user', 'content' => $content]; } } if (($role === 'assistant' || $role === 'bot') && isset($msg['openai_response_id']) && !empty($msg['openai_response_id'])) { $last_openai_response_id_from_history = $msg['openai_response_id']; } } if (!empty($user_message_text)) { $messages_payload[] = ['role' => 'user', 'content' => $user_message_text]; $latest_user_message_obj_for_stateful = ['role' => 'user', 'content' => $user_message_text]; } return [ 'messages_payload' => $messages_payload, 'latest_user_message_obj_for_stateful' => $latest_user_message_obj_for_stateful, 'last_openai_response_id_from_history' => $last_openai_response_id_from_history ]; } 